import{c as e,a7 as n,y as s,B as l}from"./chunks/framework.3cjvm90C.js";const P=JSON.parse('{"title":"TorchTitan：用于生产级 LLM 预训练的一站式 PyTorch 原生解决方案","description":"介绍TorchTitan如何提供基于PyTorch原生接口的生产级LLM预训练方案","frontmatter":{"title":"TorchTitan：用于生产级 LLM 预训练的一站式 PyTorch 原生解决方案","description":"介绍TorchTitan如何提供基于PyTorch原生接口的生产级LLM预训练方案"},"headers":[],"relativePath":"ultrascale/torch/torch_titan.md","filePath":"ultrascale/torch/torch_titan.md","lastUpdated":1782448598000}'),r={name:"ultrascale/torch/torch_titan.md"};function t(o,a,i,p,c,d){return n(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="torchtitan-用于生产级-llm-预训练的一站式-pytorch-原生解决方案" tabindex="-1">TorchTitan：用于生产级 LLM 预训练的一站式 PyTorch 原生解决方案 <a class="header-anchor" href="#torchtitan-用于生产级-llm-预训练的一站式-pytorch-原生解决方案" aria-label="Permalink to “TorchTitan：用于生产级 LLM 预训练的一站式 PyTorch 原生解决方案”">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to “摘要”">​</a></h2><p>大型语言模型（LLMs）的发展推动了自然语言处理（NLP）应用的最新技术进步。训练具有数十亿参数和数万亿 token 的 LLMs 需要复杂的分布式系统，这些系统能够组合和比较多种最先进的技术，以便在数千个加速器上高效扩展。然而，现有解决方案存在诸多不足：复杂度高、分散在多个库或存储库中、缺乏互操作性、维护繁琐。因此，整理和实证比较训练方案需要大量工程工作。</p><p>本文介绍了 TorchTitan，一个开源的、PyTorch 原生的分布式训练系统。它统一并推进了最先进的技术，简化了集成并减少了工程开销。TorchTitan 以模块化和可组合的方式无缝应用 3D 并行，同时支持弹性扩展以适应不断变化的计算需求。系统提供全面的日志记录、高效的检查点和调试工具，确保生产级训练质量。</p><p>此外， TorchTitan 结合了创新的硬件-软件协同设计方案，利用 Float8 训练和 SymmetricMemory 等尖端功能，最大限度地提高硬件利用率。作为灵活的试验平台， TorchTitan 促进了针对不同训练环境的定制方案的整理和比较。我们利用 TorchTitan 为 Llama 3.1 系列开发了优化的训练方案，并基于实践经验提供了选择和组合分布式训练技术的可操作指导。</p><p>我们在 Llama 3.1 系列 LLMs 上全面评估了 TorchTitan，涵盖 80 亿到 4050 亿参数，展示了其卓越的性能、模块化组合性和弹性扩展性。通过堆叠训练优化，基于 NVIDIA H100 GPU 的优化基线，我们取得了以下加速效果： 128-GPU 规模（Llama 3.1 8B） 1D 并行加速 65.08% ； 256-GPU 规模（Llama 3.1 70B） 2D 并行加速 12.59% ； 512-GPU 规模（Llama 3.1 405B） 3D 并行加速 30% 。</p><h2 id="_1-引言" tabindex="-1">1 引言 <a class="header-anchor" href="#_1-引言" aria-label="Permalink to “1 引言”">​</a></h2><p>LLMs 处于 NLP 进步的前沿。大型语言模型（Devlin, 2018; Liu et al., 2019; Radford et al., 2019; Chowdhery et al., 2023; Anil et al., 2023; Achiam et al., 2023; Dubey et al., 2024; Jiang et al., 2024; Abdin et al., 2024）一直是推动 NLP 应用进步的动力，涵盖语言翻译、内容/代码生成、对话式 AI、文本数据分析、创意写作、教育和研究等领域。</p><p>LLMs 需要数十亿参数和数万亿 token 的训练才能达到最先进的性能。例如， Llama 3.1 （405B 参数， 15T token， 30.84M GPU 小时， 16K H100 GPU）（Dubey et al., 2024）和 Google 的 PaLM （540B 参数， 0.8T token， 9.4M TPU 小时， 6144 TPUv4 芯片）（Chowdhery et al., 2023）。这些模型展示了卓越的自然语言理解和生成能力，但需要大量的计算资源、内存和时间来训练，突显了推动 NLP 进步所需的巨大投资。</p><p><strong>LLM 训练的挑战正在从各个方面得到解决。</strong> 大规模训练 LLMs 是一项艰巨的任务，需要在并行性、计算和通信之间取得微妙的平衡，同时应对复杂的内存和计算权衡。训练所需的巨大资源使其容易受到 GPU 故障的影响，因此需要高效的恢复机制和检查点策略以最小化停机时间（Eisenman et al., 2022; Wang et al., 2023; Gupta et al., 2024; Maurya et al., 2024; Wan et al., 2024）。</p><p>为了优化资源利用并实现弹性扩展，需要结合多种并行技术，包括数据并行（Li et al., 2020; Rajbhandari et al., 2020; Zhang et al., 2022; Zhao et al., 2023）、张量并行（Narayanan et al., 2021; Wang et al., 2022; Korthikanti et al., 2023）、上下文并行（Liu et al., 2023; Liu and Abbeel, 2024; NVIDIA, 2023; Fang and Zhao, 2024）和流水线并行（Huang et al., 2019; Narayanan et al., 2019, 2021; Qi et al., 2023）。将这些并行技术与内存和计算优化技术结合——如激活重计算（Chen et al., 2016; Korthikanti et al., 2023; He and Yu, 2023）、混合精度训练（Micikevicius et al., 2018, 2022）和深度学习编译器（Bradbury et al., 2018; Yu et al., 2023; Li et al., 2024; Ansel et al., 2024）——可最大限度地提高硬件利用率。</p><p><strong>现有系统的局限性。</strong> 虽然最先进的分布式训练技术显著推动了该领域的发展，但现有的系统在解决关键挑战方面仍然不足。这些挑战阻碍了研究人员和行业从业者的可用性、采用和有效性。</p><ol><li><strong>不可组合性</strong>：现有系统难以组合和堆叠各种并行技术，限制了多维并行的探索。进一步将它们与内存和计算优化集成具有挑战性，阻碍了训练效率的提升。</li><li><strong>不灵活和单一架构</strong>：当前系统不是模块化或可扩展的，难以集成和比较新技术、优化和硬件，限制了适应不断变化的机器学习环境的能力。</li><li><strong>硬件利用率低</strong>：当前系统未能充分利用先进的硬件功能，导致 GPU 效率低下，并且缺乏可定制的激活检查点策略来应对内存-计算权衡。</li><li><strong>对生产级训练的支持不足</strong>：现有系统缺乏可扩展和高效的分布式检查点，使得故障恢复和模型保存变得繁琐。通常不提供足够的调试工具和日志记录指标，导致难以识别和修复问题，特别是对于没有广泛专业知识的人员。</li><li><strong>未能充分利用框架潜力</strong>：现有系统未能充分利用 PyTorch 等框架的全部潜力，错过了错误修复、优化内核、新功能和编译器支持。它们还依赖于外部依赖项，这些依赖项通常缺乏全面测试，并且可能由于维护不足而过时或不兼容。</li></ol><p><strong>根本原因：缺乏表达性的张量抽象。</strong> 分布式系统不可组合性和不灵活性的根本原因，在于缺乏表达性的张量和设备抽象作为核心组件。所有分布式并行、检查点和效率优化都应在此基础上构建。</p><p><strong>设计原则：统一的分布式张量和设备抽象作为构建块。</strong> 统一的设备抽象将分布式系统表示为多维数组，每个维度对应一种并行技术，管理设备间的通信并处理集体进程组。互补的张量抽象使张量能够在此数组上进行分片，保持分片规范并支持自动分片传播。这些抽象共同实现了并行技术的无缝组合，确保了正确的语义，并促进了分布式操作的集体调度。</p><p>我们通过使用 PyTorch 的分布式张量（DTensor）和 DeviceMesh （Wanchao Liang, 2023）作为 TorchTitan 的基础组件，解决了统一张量抽象的技术挑战。通过与 DTensor 和 DeviceMesh 的合作，我们识别并解决了关键限制。基于 DTensor 的使用和扩展，我们开发了 TorchTitan ——一个生产级系统，能够在分布式训练中实现组合性、模块化、灵活性和可扩展性。TorchTitan 支持 3D 并行的组合、训练优化、可扩展的分布式检查点，并充分利用 PyTorch 生态系统的优势。</p><p>为了开发和评估 TorchTitan 的能力，我们采取了几个关键步骤，这些步骤代表了本工作的核心贡献，总结如下：</p><ol><li>我们通过扩展其分片以支持 n-D 并行、添加与 <code>torch.compile</code> 的兼容性以实现编译器优化，并通过状态字典支持实现 n-D 模型的高效检查点，推进了 DTensor 的发展。我们还解决了关键错误，增强了 DTensor 的生产准备性。</li><li>我们展示了如何组合和堆叠各种并行技术，促进了大型语言模型训练中多维并行的探索（§2.1）。</li><li>我们实现了新颖的硬件-软件协同设计解决方案，利用先进的硬件功能提高 GPU 效率，提供可定制的激活检查点策略以应对内存-计算权衡，并利用 <code>torch.compile</code> 进一步优化内存、计算和通信（§2.2）。</li><li>我们通过集成可扩展和高效的分布式检查点以促进快速故障恢复、集成 Flight Recorder 等调试工具以调试崩溃/卡住的任务，并提供广泛的日志记录指标，实现了生产级训练（§2.3）。</li><li>我们在 Llama 3.1 系列模型（8B、70B 和 405B，分别使用 1D、2D 和 3D 并行）上广泛评估了 TorchTitan，从 8 到 512 个 GPU 的规模，展示了弹性扩展性，同时确保了效率、收敛性和准确性。总结来说，我们在 128-GPU 规模上展示了 1D 并行加速 65.08% ，在 256-GPU 规模上展示了 2D 并行加速 12.59% ，在 512-GPU 规模上展示了 3D 并行加速 30% ，基于最新的 NVIDIA H100 GPU 的优化基线（§3.2）。</li><li>我们提供了系统的训练方案和指南，帮助用户应对分布式训练的复杂性，优化各种模型大小和集群配置的训练效率（§3.3）。</li><li>我们展示了模块化和可扩展架构如何无缝集成和比较新技术、优化和硬件，确保适应不断变化的机器学习环境（§4）。</li></ol><p>通过提供一个易于访问和可扩展的平台， TorchTitan 使 LLM 预训练民主化，使更广泛的研究人员和开发人员能够利用 LLM 的潜力，加速该领域的创新。</p><h2 id="_2-通过组合性实现弹性" tabindex="-1">2 通过组合性实现弹性 <a class="header-anchor" href="#_2-通过组合性实现弹性" aria-label="Permalink to “2 通过组合性实现弹性”">​</a></h2><p>TorchTitan 以模块化的方式结合各种并行技术，使用户能够轻松选择多维并行的组合。这种组合性增强了前沿探索的便利性，解决了难以扩展的挑战，从而优化大规模训练效率。</p><p>TorchTitan 的代码库经过精心组织以实现组合性和可扩展性。我们特意将三个主要组件分开并尽可能正交：（1）模型定义——并行无关，设计为可读性强；（2）并行助手——将数据并行、张量并行和流水线并行应用于特定模型；（3）通用训练循环。所有组件均可通过 TOML 文件配置，并支持命令行覆盖，便于添加新模型和并行技术。</p><h3 id="可组合的-n-d-并行训练" tabindex="-1">可组合的 N-D 并行训练 <a class="header-anchor" href="#可组合的-n-d-并行训练" aria-label="Permalink to “可组合的 N-D 并行训练”">​</a></h3><p>在本节中，我们将介绍在大规模集群上扩展模型训练的整个流程，包括元设备初始化和核心的可组合多维并行，以展示这些技术如何组合在一起，在 TorchTitan 中高效地训练 LLMs。TorchTitan 中的实际代码片段可以在附录 A 中找到。</p><h4 id="_2-1-1-使用元设备进行大规模模型初始化" tabindex="-1">2.1.1 使用元设备进行大规模模型初始化 <a class="header-anchor" href="#_2-1-1-使用元设备进行大规模模型初始化" aria-label="Permalink to “2.1.1 使用元设备进行大规模模型初始化”">​</a></h4><p>鉴于 LLMs 模型大小的指数增长，第一个扩展问题甚至在训练开始之前就出现了——需要在集群上实例化一个大模型以进行分片，而不会溢出 CPU 或 GPU 内存。</p><p>为了解决这个问题，我们在 TorchTitan 中启用了元设备初始化模型，其中模型首先在&quot;元&quot;设备类型上初始化。元设备张量仅保存元数据信息，而不是实际数据，使初始化速度极快。之后，我们执行模型分片并将模型参数转换为分布式张量（DTensors），其中每个参数保存一个位于元设备上的本地分片。最后，我们根据用户定义的初始化函数执行参数初始化。我们利用分布式张量正确同步随机数生成器（RNG）种子，并根据其分片布局初始化参数。这确保了参数与在分片之前在一个设备上初始化整个模型时具有相同的值，从而便于不同并行配置之间的收敛比较。</p><h4 id="_2-1-2-完全分片数据并行" tabindex="-1">2.1.2 完全分片数据并行 <a class="header-anchor" href="#_2-1-2-完全分片数据并行" aria-label="Permalink to “2.1.2 完全分片数据并行”">​</a></h4><p>原始的完全分片数据并行（FSDP）（Zhao et al., 2023）是 ZeRO 的有效实现，提供了在 PyTorch 中训练大模型的能力。然而， PyTorch 中的原始实现（FSDP1）由于 FlatParameter 实现而存在各种限制（详见附录 B.1）。</p><p>鉴于这些限制， TorchTitan 集成了新版本的完全分片数据并行（FSDP2）。它使用每个参数的分布式张量分片表示，从而提供了更好的与模型并行技术和其他需要操作单个参数的功能的组合性。</p><p>TorchTitan 集成并利用 FSDP2 作为其默认的 1D 并行，受益于改进的内存管理（通常比 FSDP1 低 7% 的每 GPU 内存需求）和轻微的性能提升（平均比 FSDP1 快 1.5% ）。有关 FSDP2 和使用示例的更多详细信息，请参见附录 B.1。TorchTitan 通过嵌入适当的默认值（包括自动分片与世界大小匹配）使运行 FSDP2 变得简单。</p><p>为了扩展到更大的世界大小， TorchTitan 还集成了混合分片数据并行（HSDP），它通过创建分片组扩展了 FSDP2。详细信息请参见附录 B.2。</p><h4 id="_2-1-3-张量并行" tabindex="-1">2.1.3 张量并行 <a class="header-anchor" href="#_2-1-3-张量并行" aria-label="Permalink to “2.1.3 张量并行”">​</a></h4><p>张量并行（TP）（Narayanan et al., 2021）与序列并行（SP）（Korthikanti et al., 2023）一起，是使大规模模型训练成为可能的关键模型并行技术。</p><p><img src="https://arxiv.org/html/2410.06511v2/extracted/5976575/figures/titan-workflow.png" alt="Refer to caption"></p><p>图 1：可组合和模块化的 TorchTitan 初始化工作流程。</p><p>TP 在 TorchTitan 中使用 PyTorch 的 <code>RowwiseParallel</code> 和 <code>ColwiseParallel</code> API 实现，其中模型参数被分区为 DTensors 并执行分片计算。通过利用 DTensor， TP 实现不需要触及模型代码，这使得在不同模型上更快地启用，并提供了与本文中提到的其他功能的更好组合性。</p><p><strong>张量和序列并行（TP/SP）</strong>：虽然 TP 分区了计算量最大的部分，但序列并行（SP）在序列维度上执行归一化或 dropout 层的分片计算。否则会生成大量复制的激活张量，从而对每个 GPU 的内存限制构成挑战。有关 TP 和 FSDP + TP 的更多详细信息、说明和用法，请参见附录 B.3。</p><p>由于 TP 和 SP 之间的协同关系， TorchTitan 原生将这两者捆绑在一起，并通过 TP 度设置共同控制。</p><p><strong>损失并行</strong>：当计算损失函数时，模型输出通常非常大。由于 TP/SP 的模型输出在（通常很大的）词汇维度上分片，直接计算交叉熵损失需要沿 TP 维度收集所有分片以使输出复制，这会导致大量内存使用。</p><p>通过损失并行，可以高效地计算交叉熵损失，而无需将所有模型输出分片收集到每个 GPU。这不仅显著减少了内存消耗，还通过减少通信开销和并行执行分片计算提高了训练速度。鉴于这些改进， TorchTitan 默认实现了损失并行。</p><h4 id="_2-1-4-流水线并行" tabindex="-1">2.1.4 流水线并行 <a class="header-anchor" href="#_2-1-4-流水线并行" aria-label="Permalink to “2.1.4 流水线并行”">​</a></h4><p>对于最大规模的预训练， TorchTitan 提供了流水线并行。由于具有最轻的通信开销并利用 P2P 通信，流水线并行变得至关重要。</p><p>流水线并行（PP）将模型视为一系列操作，将操作（及其使用的参数）分块为 S 个阶段，这些阶段在单独的设备组上运行。在典型情况下，一个阶段代表单个模型层或一组 N 个相邻的模型层，但在理论上它甚至可以是一个部分层。对于前向传递，一个阶段接收输入激活（阶段 0 除外），执行本地计算，并发送输出激活（阶段 S-1 除外）。最后一个阶段执行损失计算，并开始反向传递，通过流水线反向发送梯度。为了提高效率，输入批次被分解为微批次，流水线调度将一个微批次的计算与其他微批次的通信重叠。TorchTitan 支持多种流水线调度，其调度已在其他工作中描述（Narayanan et al., 2019; Huang et al., 2019; Narayanan et al., 2021; Qi et al., 2023）。</p><p>训练循环还必须考虑流水线阶段的创建，并执行流水线调度而不是直接调用 <code>model_forward()</code>。由于调度按微批次计算损失，因此损失计算和任何日志记录代码必须为 PP 更新。在 TorchTitan 中，我们建议定义一个共享的 <code>loss_fn</code>，用于流水线和非流水线代码路径，从而最小化训练循环中的分歧。</p><p>与数据并行的交互——例如确保数据并行减少仅在调度中的最后一个微批次之后发生，以及在使用 ZeRO-3 时调度分片和取消分片操作——也在流水线调度执行器中透明地处理，简化了 TorchTitan 中的训练器实现。有关其在 TorchTitan 中的用法，请参见附录 B.4。</p><h3 id="优化训练效率" tabindex="-1">优化训练效率 <a class="header-anchor" href="#优化训练效率" aria-label="Permalink to “优化训练效率”">​</a></h3><h4 id="_2-2-1-使用激活检查点导航计算-内存权衡" tabindex="-1">2.2.1 使用激活检查点导航计算-内存权衡 <a class="header-anchor" href="#_2-2-1-使用激活检查点导航计算-内存权衡" aria-label="Permalink to “2.2.1 使用激活检查点导航计算-内存权衡”">​</a></h4><p>激活检查点（AC）（Chen et al., 2016）和选择性激活检查点（SAC）（Korthikanti et al., 2023）是标准的训练技术，通过在反向传递期间重新计算激活来减少峰值 GPU 内存使用。即使在应用多维并行之后，通常也需要它。</p><p>TorchTitan 提供了灵活的 AC 和 SAC 选项，利用 <code>torch.utils.checkpoint</code> 在 TransformerBlock 级别应用。AC 策略包括&quot;完整&quot;AC、操作级 SAC 和层级 SAC。</p><p>在 TransformerBlock 中，完整 AC 通过在反向传递期间重新计算所有需要的激活张量来工作。操作级 SAC 保存计算密集型的 PyTorch 操作的结果，并仅重新计算其他操作。层级 SAC 的工作方式与完整 AC 类似，但包装应用于每 x 个 TransformerBlock （其中 x 由用户指定），以实现内存和重新计算之间的可配置权衡。（详细信息见附录 B.5。）</p><h4 id="_2-2-2-区域编译以利用-torch-compile-优化" tabindex="-1">2.2.2 区域编译以利用 torch.compile 优化 <a class="header-anchor" href="#_2-2-2-区域编译以利用-torch-compile-优化" aria-label="Permalink to “2.2.2 区域编译以利用 torch.compile 优化”">​</a></h4><p><code>torch.compile</code> 在 PyTorch 2 中发布（Ansel et al., 2024）。TorchDynamo 作为前端将 PyTorch 操作提取到 FX 图中， TorchInductor 作为后端将 FX 图编译为融合的 Triton 代码以提高性能。</p><p>在 TorchTitan 中，我们使用区域编译，将 <code>torch.compile</code> 应用于 Transformer 模型中的每个单独的 TransformerBlock。这有两个主要好处：（1）我们为每个区域获得一个完整的图（没有图中断），与 FSDP2 和 TP （以及更一般的 <code>torch.Tensor</code> 子类，如 DTensor）和其他 PyTorch 分布式训练技术兼容；（2）由于 Llama 模型将相同的 TransformerBlock 层堆叠在一起，<code>torch.compile</code> 可以识别重复编译的相同结构，只编译一次，从而大大减少编译时间。</p><p><code>torch.compile</code> 通过计算融合和计算-通信重新排序，以模型无关的方式和简单的用户界面带来了吞吐量和内存效率（见第 3.2 节）。下面我们进一步说明 <code>torch.compile</code> 的组合性如何帮助 TorchTitan 通过简单的用户界面解锁硬件优化的性能增益，结合异步 TP 和 Float8 等高级功能。</p><h4 id="_2-2-3-异步张量并行以最大程度地重叠通信" tabindex="-1">2.2.3 异步张量并行以最大程度地重叠通信 <a class="header-anchor" href="#_2-2-3-异步张量并行以最大程度地重叠通信" aria-label="Permalink to “2.2.3 异步张量并行以最大程度地重叠通信”">​</a></h4><p>默认情况下， TP 在分片计算之前/之后会引发阻塞通信，导致计算资源无法有效利用。异步 TP （AsyncTP）（Wang et al., 2022）通过将注意力模块和前馈模块中的 TP 矩阵乘法分解为较小的块，并在每个部分之间重叠通信集体，实现了计算-通信重叠。重叠是通过微流水线优化实现的，其中结果在计算其他块的同时进行通信。</p><p>PyTorch AsyncTP 基于 SymmetricMemory 抽象，它创建节点内缓冲区以编写更快的通信集体（Wang et al., 2024）。这是通过在每个 GPU 上分配一个共享内存缓冲区来实现的，以提供直接的 P2P 访问。</p><p>通过 TorchTitan 集成 <code>torch.compile</code>，可以轻松配置 AsyncTP 以在较新的硬件（H100 或具有节点内 NVSwitch 的较新 GPU）上实现有意义的端到端加速（详见第 3.2 节）。使用详情见附录 B.6。</p><h4 id="_2-2-4-通过混合精度训练和-float8-支持提高吞吐量" tabindex="-1">2.2.4 通过混合精度训练和 Float8 支持提高吞吐量 <a class="header-anchor" href="#_2-2-4-通过混合精度训练和-float8-支持提高吞吐量" aria-label="Permalink to “2.2.4 通过混合精度训练和 Float8 支持提高吞吐量”">​</a></h4><p>混合精度训练（Micikevicius et al., 2018）在确保训练稳定性的同时提供了内存和计算节省。FSDP2 内置支持混合精度训练，使用基本的 <code>torch.dtype</code>。这涵盖了在低精度（例如 <code>torch.bfloat16</code>）中执行 FSDP 全收集和计算的流行用法，并在高精度（例如 <code>torch.float32</code>）中执行无损 FSDP 减少分散（梯度）以获得更好的数值结果。使用详情见附录 B.7。</p><p>TorchTitan 还支持在较新的硬件（如 H100）上使用 Float8 （派生数据类型）进行更高级的混合精度训练，具有显著的性能提升（见第 3.2 节报告）。<code>torchao.float8</code> 的 Float8 功能支持多种每张量缩放策略，包括动态、延迟和静态（见 Micikevicius et al. (2022); Vasiliy Kuznetsov (2024), 第 4.3 节），同时与其他关键的 PyTorch 原生系统（如 autograd、<code>torch.compile</code>、FSDP2 和 TP）组合。</p><h3 id="生产级训练" tabindex="-1">生产级训练 <a class="header-anchor" href="#生产级训练" aria-label="Permalink to “生产级训练”">​</a></h3><p>为了实现生产级训练， TorchTitan 提供了开箱即用的关键功能无缝集成。这些功能包括：（1）使用 PyTorch 分布式检查点（DCP）进行高效检查点；（2）通过集成 Flight Recorder 调试卡住或崩溃的任务。</p><h4 id="_2-3-1-可扩展和高效的分布式检查点" tabindex="-1">2.3.1 可扩展和高效的分布式检查点 <a class="header-anchor" href="#_2-3-1-可扩展和高效的分布式检查点" aria-label="Permalink to “2.3.1 可扩展和高效的分布式检查点”">​</a></h4><p>检查点在训练大型语言模型中至关重要，原因有两个：它们促进了模型在推理和评估等应用中的重用，并在发生故障时提供了恢复机制。最佳的检查点工作流程应确保在不同并行性之间轻松重用，并在不减慢训练速度的情况下保持高性能。</p><p>有两种典型的检查点方法。第一种方法将状态（模型参数和优化器状态）聚合为一个不分片的版本，该版本与并行性无关，便于重用但需要昂贵的通信。第二种方法让每个训练器保存其本地分片状态，这加快了过程但由于嵌入的并行性信息而使重用变得复杂。</p><p>DCP 使用 DTensor 解决了这些挑战。DTensor 封装了全局和本地张量信息，独立于并行性。DCP 将此信息转换为内部格式进行存储。在加载时， DCP 将存储的分片与当前基于 DTensor 的模型参数和优化器状态进行匹配，从存储中获取必要的分片。TorchTitan 利用所有原生 PyTorch 并行性，有效地使用 DCP 来平衡效率和可用性。此外， DCP 通过异步检查点提高了效率，在单独的线程中处理存储持久性，使此操作与后续训练迭代重叠。TorchTitan 利用 DCP 的异步检查点将 Llama 3.1 8B 模型的检查点开销减少了 5-15 倍（Zhang et al., 2024; Huang et al., 2024）。</p><h4 id="_2-3-2-使用-flight-recorder-调试任务崩溃" tabindex="-1">2.3.2 使用 Flight Recorder 调试任务崩溃 <a class="header-anchor" href="#_2-3-2-使用-flight-recorder-调试任务崩溃" aria-label="Permalink to “2.3.2 使用 Flight Recorder 调试任务崩溃”">​</a></h4><p>在开发并行代码或大规模运行时，常见的故障模式是观察到 NCCL 集体超时，然后需要找出根本原因。由于通信内核通常从 CPU 的角度是异步的，当某些东西超时时，很难确定哪个操作失败以及为什么失败。PyTorch 提供了一个用于 NCCL 集体的 Flight Recorder 来帮助解决这个难题。它记录了每个集体或 P2P 操作的开始和结束时间（在 GPU 上）以及入队时间（在 CPU 上）。此外，它还记录了元数据，例如使用了哪个进程组、源排名（对于 P2P，还有目的地）、张量大小和堆栈跟踪。</p><p>我们发现 Flight Recorder 中包含的数据有助于调试由并行代码中的错误引起的集体挂起和 P2P 挂起。对于 PP，可能存在调度错误导致挂起，由于缺少或错误排序的发送或接收操作。基于 Flight Recorder 数据的分析可以确定在 GPU 上完成的最新发送或接收。对于 FSDP 或 TP，可以确定一个或多个排名是否未调用集体，可能是由于 PP 调度中的错误或 TP 中的错误逻辑。</p><h2 id="_3-实验" tabindex="-1">3 实验 <a class="header-anchor" href="#_3-实验" aria-label="Permalink to “3 实验”">​</a></h2><p>在本节中，我们通过在 Llama 3.1 8B、70B 和 405B 上进行的实验，从 1D 并行到 3D 并行（分别），在 8 到 512 个 GPU 的规模上展示了使用 TorchTitan 进行弹性分布式训练的有效性。我们还分享了通过 TorchTitan 实验获得的知识和经验。有关如何应用（最多） 3D 并行的代码库演练可以在附录 A 中找到。</p><h3 id="实验设置" tabindex="-1">实验设置 <a class="header-anchor" href="#实验设置" aria-label="Permalink to “实验设置”">​</a></h3><p>实验在具有 95 GiB 内存的 NVIDIA H100 GPU 上进行，每个主机配备 8 个 GPU 和 NVSwitch。两个主机形成一个机架，连接到 TOR 交换机。后端 RDMA 网络连接 TOR 交换机。在 TorchTitan 中，我们集成了一个可检查点的数据加载器，并为 C4 数据集（en 变体）提供了内置支持，这是 Common Crawl 的网络爬取语料库的一个巨大、清理过的版本（Raffel et al., 2020）。我们在本节的所有实验中使用相同的数据集。对于分词器，我们使用与 Llama 3.1 一起发布的官方分词器（tiktoken）。</p><blockquote><p>脚注 1：用于实验的 H100 GPU 是非标准的。它们具有 HBM2e，并且限制在较低的 TDP。实际峰值 TFLOPs 应在 SXM 和 NVL 之间，我们不知道确切值。</p></blockquote><h3 id="性能" tabindex="-1">性能 <a class="header-anchor" href="#性能" aria-label="Permalink to “性能”">​</a></h3><p>为了展示 TorchTitan 的弹性和可扩展性，我们在广泛的 GPU 规模（从 8 到 512）上进行了实验，随着基础模型大小的增加（8B、70B 和 405B），并行维度数量不同（分别为 1D、2D 和 3D）。为了展示第 2.2 节中引入的优化技术的有效性，我们展示了在适当基线上添加每个单独技术时训练吞吐量的提高。特别是，当在更高维度的并行性上训练新功能时，基线始终更新为包括所有先前的技术。</p><p>我们注意到，在整个实验过程中，内存读数保持稳定，而吞吐量数字（每秒 token，每 GPU）每 10 次迭代计算并记录一次，并且始终在第 90 次迭代读取。我们不报告模型 FLOPS 利用率（MFU）（Chowdhery et al., 2023），因为当在 TorchTitan 中启用 Float8 时， BF16 Tensor Core 和 FP8 Tensor Core 都参与模型训练，但它们具有不同的峰值 FLOPS，在这种情况下 MFU 的定义不明确。我们注意到， 1D Llama 3.1 8B 模型在 8 或 128 个 H100 GPU 上训练而不启用 Float8 时，实现了 33% 到 42% 的 MFU。</p><blockquote><p>脚注 2：不同的 PP 排名可能具有不同的峰值内存使用量。我们取所有 GPU 的最大值。</p></blockquote><p>表 1： 1D 并行（FSDP）在 Llama 3.1 8B 模型上， 8 个 GPU。混合精度训练。选择性激活检查点。本地批次大小 2，全局批次大小 16。</p><table tabindex="0"><thead><tr><th>技术</th><th>吞吐量（Tok/Sec）</th><th>比较</th><th>内存（GiB）</th></tr></thead><tbody><tr><td>FSDP</td><td>6,258</td><td>100%</td><td>81.9</td></tr><tr><td>+ torch.compile</td><td>6,674</td><td>+ 6.64%</td><td>77.0</td></tr><tr><td>+ torch.compile + Float8</td><td>9,409</td><td>+ 50.35%</td><td>76.8</td></tr></tbody></table><p>表 2： 1D 并行（FSDP）在 Llama 3.1 8B 模型上， 128 个 GPU。混合精度训练。选择性激活检查点。本地批次大小 2，全局批次大小 256。</p><table tabindex="0"><thead><tr><th>技术</th><th>吞吐量（Tok/Sec）</th><th>比较</th><th>内存（GiB）</th></tr></thead><tbody><tr><td>FSDP</td><td>5,645</td><td>100%</td><td>67.0</td></tr><tr><td>+ torch.compile</td><td>6,482</td><td>+ 14.82%</td><td>62.1</td></tr><tr><td>+ torch.compile + Float8</td><td>9,319</td><td>+ 65.08%</td><td>61.8</td></tr></tbody></table><p>表 3： 2D 并行（FSDP + TP）+ torch.compile + Float8 在 Llama 3.1 70B 模型上， 256 个 GPU。混合精度训练。完整激活检查点。FSDP 度 32， TP 度 8。本地批次大小 16，全局批次大小 512。</p><table tabindex="0"><thead><tr><th>技术</th><th>吞吐量（Tok/Sec）</th><th>比较</th><th>内存（GiB）</th></tr></thead><tbody><tr><td>2D</td><td>897</td><td>100%</td><td>70.3</td></tr><tr><td>+ AsyncTP</td><td>1,010</td><td>+ 12.59%</td><td>67.7</td></tr></tbody></table><h3 id="使用-torchtitan-3d-并行进行扩展" tabindex="-1">使用 TorchTitan 3D 并行进行扩展 <a class="header-anchor" href="#使用-torchtitan-3d-并行进行扩展" aria-label="Permalink to “使用 TorchTitan 3D 并行进行扩展”">​</a></h3><p>LLM 扩展定律由于越来越大的模型大小和大量数据而带来了挑战，这需要在大量 GPU 上应用并行策略。TorchTitan 提供了组合不同并行性的能力，以高效地将模型训练扩展到数千个 GPU。本节讨论了在训练大规模 LLM 时应用 TorchTitan 3D 并行的观察和动机。请注意，可能有许多 3D 并行组合，但在本文中我们选择只讨论一种组合，可以总结为以下图表：</p><h4 id="_3-3-1-使用-fsdp-进行扩展" tabindex="-1">3.3.1 使用 FSDP 进行扩展 <a class="header-anchor" href="#_3-3-1-使用-fsdp-进行扩展" aria-label="Permalink to “3.3.1 使用 FSDP 进行扩展”">​</a></h4><p>FSDP （ZeRO）是一种通用技术，可以应用于任何模型架构，使其成为第一个或唯一的并行度的好选择。只要 FSDP 通信比相应的计算快（对于在多达数百个如 512 个 GPU 上训练的 LLM 来说是这样），并且不需要将（有效）每 GPU 批次大小减少到 1 以下（出于下面 TP 部分提到的原因）， 1D FSDP 应该足够了。</p><p>现有的基于环的 NCCL 集体实现（全收集、减少分散）将产生延迟开销，这在大规模（例如 512 个 GPU）时变得严重。单独的 FSDP 将由于集体延迟随着世界大小的增加而线性增加，导致 FSDP 集体无法被计算隐藏而变得效率低下。为了进一步扩展，需要考虑结合模型并行解决方案，如 TP 和 PP。</p><h4 id="_3-3-2-2d-并行-将-tp-与-fsdp-结合" tabindex="-1">3.3.2 2D 并行：将 TP 与 FSDP 结合 <a class="header-anchor" href="#_3-3-2-2d-并行-将-tp-与-fsdp-结合" aria-label="Permalink to “3.3.2 2D 并行：将 TP 与 FSDP 结合”">​</a></h4><p>模型并行（TP 和 PP）可以帮助避免单独扩展 FSDP 时面临的增加的集体延迟。TP 可以进一步降低有效的本地批次大小（当本地批次大小设置为 1 时，最小为 TP 度），因为 TP 分片模型在多个 GPU 上共同处理同一批次。这对于减少峰值内存使用至关重要，以便训练可以适应 GPU 内存（例如由于大模型大小或序列长度），或者对于具有固定所需全局批次大小的强扩展（例如由于训练效率考虑）。</p><p>此外， TP 执行特征维度分片，这可以带来更优化的矩阵乘法形状，以实现更好的 FLOP 利用率。</p><p>由于 TP 引入了额外的阻塞集体，实际上 TP 仅在具有快速互连（NVLink）的节点内应用。AsyncTP 可以通过完全重叠通信来提高性能。</p><p>表 4： 3D 并行（FSDP + TP + PP）+ torch.compile + Float8 + AsyncTP 在 Llama 3.1 405B 模型上， 512 个 GPU。混合精度训练。完整激活检查点。FSDP 度 4， TP 度 8， PP 度 16。本地批次大小 32，全局批次大小 128。</p><table tabindex="0"><thead><tr><th>调度</th><th>吞吐量（Tok/Sec）</th><th>比较</th><th>内存（GiB）</th></tr></thead><tbody><tr><td>IF1B</td><td>100</td><td>100%</td><td>78.0</td></tr><tr><td>交错 IF1B</td><td>130</td><td>+ 30.00%</td><td>80.3</td></tr></tbody></table><p><img src="https://arxiv.org/html/2410.06511v2/extracted/5976575/figures/scale_3d_parallel.png" alt="Refer to caption"></p><p>图 2：使用 3D 并行进行扩展</p><h4 id="_3-3-3-3d-并行-将-pp-与-2d-并行结合" tabindex="-1">3.3.3 3D 并行：将 PP 与 2D 并行结合 <a class="header-anchor" href="#_3-3-3-3d-并行-将-pp-与-2d-并行结合" aria-label="Permalink to “3.3.3 3D 并行：将 PP 与 2D 并行结合”">​</a></h4><p>与其他模型并行相比， PP 通过仅在阶段之间以 P2P 方式传输激活和梯度，需要较少的通信带宽。它特别有用：（1）当 FSDP 世界大小再次变大时， FSDP+TP 仍然暴露 FSDP 集体时，进一步减少 FSDP 通信延迟；或（2）在带宽有限的集群上进行训练。</p><p>我们注意到， PP 的性能，特别是&quot;气泡&quot;大小，可能会因使用的流水线调度和微批次大小而异，假设固定的全局批次大小和世界大小。</p><h2 id="_4-展示适应性和可扩展性" tabindex="-1">4 展示适应性和可扩展性 <a class="header-anchor" href="#_4-展示适应性和可扩展性" aria-label="Permalink to “4 展示适应性和可扩展性”">​</a></h2><p>在本节中，我们通过突出正在进行的工作和外部贡献，展示了 TorchTitan 的适应性和可扩展性，这些贡献展示了其无缝集成和比较新技术、优化和模型的能力。</p><h3 id="正在进行的工作-4d-并行和零气泡流水线调度" tabindex="-1">正在进行的工作： 4D 并行和零气泡流水线调度 <a class="header-anchor" href="#正在进行的工作-4d-并行和零气泡流水线调度" aria-label="Permalink to “正在进行的工作： 4D 并行和零气泡流水线调度”">​</a></h3><p>TorchTitan 的模块化和可扩展架构使得无缝集成新技术和优化成为可能。例如，正在进行的工作包括集成上下文并行（Liu et al., 2023; Liu and Abbeel, 2024; NVIDIA, 2023）以实现 4D 并行，并利用 <code>torch.distributed_pipelining</code> 包支持零气泡调度（Qi et al., 2023）。这展示了 TorchTitan 适应不断变化的机器学习环境的能力。</p><h3 id="外部贡献-构建和评估自定义创新" tabindex="-1">外部贡献：构建和评估自定义创新 <a class="header-anchor" href="#外部贡献-构建和评估自定义创新" aria-label="Permalink to “外部贡献：构建和评估自定义创新”">​</a></h3><p>TorchTitan 的灵活架构还使用户能够轻松集成和比较新创新。通过提供一个模块化和高效的试验平台， TorchTitan 使用户能够快速基准测试新技术、优化和硬件对其训练性能的影响。这已经导致了一个新的生产级数据加载器的改进、一个新的 ZeRO 实现的改进、一个基于 Adam 的优化器的进步，以及一个顶级扩散模型的训练。</p><h2 id="_5-相关工作" tabindex="-1">5 相关工作 <a class="header-anchor" href="#_5-相关工作" aria-label="Permalink to “5 相关工作”">​</a></h2><p>随着 LLM 的快速增长（Dubey et al., 2024; Achiam et al., 2023），有大量的研究和行业关注于改进训练各种大小的 LLM 的基础设施。由于这些模型的本质是大规模的，分布式训练支持变得不可避免。像 Megatron （Narayanan et al., 2021）、DeepSpeed （Rasley et al., 2020）和 PyTorch 分布式（Paszke et al., 2019; Meta Platforms, Inc.）这样的库提供了构建分布式训练工作流程的 API。NVIDIA NeMo （NVIDIA Corporation, 2024）基于 Megatron-LM，提供了一个处理复杂端到端模型生命周期的打包解决方案，从数据管理到模型部署。PyTorch 原生解决方案如 torchtune （Meta Platforms, Inc.）专注于在简化的工作流程中微调 LLM。TorchTitan 与这些解决方案的不同之处在于，它专注于使用 PyTorch 原生 API 进行生产级预训练。该库设计具有弹性组合性，以适应预训练 LLM 所需的规模，同时最小化外部依赖。这降低了解释和扩展预训练的门槛，同时提供了异步分布式检查点等功能，以构建端到端生产工作流程。</p><h2 id="_6-结论" tabindex="-1">6 结论 <a class="header-anchor" href="#_6-结论" aria-label="Permalink to “6 结论”">​</a></h2><p>TorchTitan 是一个强大而灵活的框架，用于训练 LLM。它提供了组合性，允许用户结合各种并行技术（FSDP、TP 和 PP）、内存优化方法（Float8 和激活检查点），以及与 <code>torch.compile</code> 的集成以优化训练效率。TorchTitan 高度灵活，适应不断变化的模型架构和硬件进步，并具有模块化设计和多轴指标，促进创新和实验。TorchTitan 还优先考虑可解释性、生产级训练和 PyTorch 原生能力。</p><p>此外，它提供了具有弹性扩展性的高性能训练、全面的训练方案和指南，以及选择和组合分布式训练技术的专家指导。如实验部分所示， TorchTitan 在 128-GPU 规模（Llama 3.1 8B）上提供了 1D 并行加速 65.08% ，在 256-GPU 规模（Llama 3.1 70B）上提供了 2D 并行加速 12.59% ，在 512-GPU 规模（Llama 3.1 405B）上提供了 3D 并行加速 30% ，基于优化基线。凭借其强大的功能和高效率， TorchTitan 是挑战性 LLM 训练任务的理想一站式解决方案。</p><h2 id="附录-a-可组合的-3d-并行演练" tabindex="-1">附录 A 可组合的 3D 并行演练 <a class="header-anchor" href="#附录-a-可组合的-3d-并行演练" aria-label="Permalink to “附录 A 可组合的 3D 并行演练”">​</a></h2><p>我们已经讨论了使用 TorchTitan 3D 并行进行扩展以及应用不同并行性将训练扩展到数千个 GPU 的动机。在本节中，我们将演练 TorchTitan 中的 3D 并行代码。</p><p>第一步是在元设备上创建模型实例（例如 Llama 模型的 <strong>Transformer</strong>）。然后，我们根据 <code>pipeline_parallel_split_points</code> 配置将模型拆分为多个 PP 阶段。请注意，对于循环调度的 PP，我们可能会从 PP 拆分中获得多个 <code>model_parts</code>，其中 <code>model_parts</code> 中的每个项目都是一个阶段模型块。接下来，我们为每个模型部分应用 SPMD 风格的分布式训练技术，包括 TP、激活检查点、<code>torch.compile</code>、FSDP 和混合精度训练，然后实际在 GPU 上初始化分片模型。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 元初始化</span></span>
<span class="line"><span>with torch.device(&quot;meta&quot;):</span></span>
<span class="line"><span>    model = model_cis.from_model_args(model_config)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 应用PP</span></span>
<span class="line"><span>pp_schedule, model_parts = models_pipelining_fns(model_name)(</span></span>
<span class="line"><span>    model, pp_mesh, parallel_dims, job_config, device, model_config, loss_fn</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span>for m in model_parts:</span></span>
<span class="line"><span>    # 应用SPMD风格的分布式训练技术</span></span>
<span class="line"><span>    models_parallelize_fns(model_name)(m, world_mesh, parallel_dims, job_config)</span></span>
<span class="line"><span>    # 将分片模型移动到GPU并通过DTensor初始化权重</span></span>
<span class="line"><span>    m.to_empty(device=&quot;cuda&quot;)</span></span>
<span class="line"><span>    m.init_weights()</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>为了将 PP 应用于模型，我们在高层运行以下代码。<code>pipeline_llama_manual_split</code> 根据手动提供的 <code>pipeline_parallel_split_points</code> 配置将模型拆分为多个阶段，通过从完整模型（在元设备上）中删除未使用的模型组件。然后，<code>build_pipeline_schedule</code> 使用 <code>torch.distributed.pipelining</code> 中的各种选项创建流水线调度，包括 IF1B （Narayanan et al., 2019）、GPipe （Huang et al., 2019）、交错 IF1B （Narayanan et al., 2021）等，由 <code>pipeline_parallel_schedule</code> 配置指示。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>stages, models = pipeline_llama_manual_split(</span></span>
<span class="line"><span>    model, pp_mesh, parallel_dims, job_config, device, model_config</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span>pp_schedule = build_pipeline_schedule(job_config, stages, loss_fn)</span></span>
<span class="line"><span>return pp_schedule, models</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>TP 和 FSDP 在 SPMD 风格的 <code>models_parallelize_fns</code> 函数中应用。为了应用 TP，我们利用 DTensor <code>parallelize_module</code> API，通过提供 TP&quot;计划&quot;作为模型参数应如何分片的指令。在下面的示例中，我们展示了（不完整的）代码，用于分片重复的 TransformerBlock。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>for layer_id, transformer_block in model.layers.items():</span></span>
<span class="line"><span>    layer_tp_plan = {</span></span>
<span class="line"><span>        &quot;attention_norm&quot;: SequenceParallel(),</span></span>
<span class="line"><span>        &quot;attention&quot;: PrepareModuleInput(</span></span>
<span class="line"><span>            input_layouts=(Shard(1), None),</span></span>
<span class="line"><span>            desired_input_layouts=(Replicate(), None),</span></span>
<span class="line"><span>        ),</span></span>
<span class="line"><span>        &quot;attention.wq&quot;: ColwiseParallel(),</span></span>
<span class="line"><span>        ...</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    parallelize_module(</span></span>
<span class="line"><span>        module=transformer_block,</span></span>
<span class="line"><span>        device_mesh=tp_mesh,</span></span>
<span class="line"><span>        parallelize_plan=layer_tp_plan,</span></span>
<span class="line"><span>    )</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><p>最后，我们通过包装每个单独的 TransformerBlock 然后包装整个模型来应用 FSDP。请注意， PyTorch 中的 FSDP2 实现支持混合精度训练。默认情况下，我们在参数全收集和激活计算中使用 <code>torch.float16</code>，在梯度减少分散通信和优化器更新中使用 <code>torch.float32</code>。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>mp_policy = MixedPrecisionPolicy(param_dtype, reduce_dtype)</span></span>
<span class="line"><span>fsdp_config = {&quot;mesh&quot;: dp_mesh, &quot;mp_policy&quot;: mp_policy}</span></span>
<span class="line"><span>for layer_id, transformer_block in model.layers.items():</span></span>
<span class="line"><span>    # 作为优化，不为最后一个TransformerBlock重新分片，因为FSDP会立即预取它</span></span>
<span class="line"><span>    reshard_after_forward = int(layer_id) &lt; len(model.layers) - 1</span></span>
<span class="line"><span>    fully_shard(</span></span>
<span class="line"><span>        transformer_block,</span></span>
<span class="line"><span>        **fsdp_config,</span></span>
<span class="line"><span>        reshard_after_forward=reshard_after_forward,</span></span>
<span class="line"><span>    )</span></span>
<span class="line"><span>fully_shard(model, **fsdp_config)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="附录-b-补充材料" tabindex="-1">附录 B 补充材料 <a class="header-anchor" href="#附录-b-补充材料" aria-label="Permalink to “附录 B 补充材料”">​</a></h2><h3 id="完全分片数据并行" tabindex="-1">完全分片数据并行 <a class="header-anchor" href="#完全分片数据并行" aria-label="Permalink to “完全分片数据并行”">​</a></h3><p>FSDP2 改进了原始 FSDP1 的 FlatParameter 分组。具体来说，参数现在表示为在张量维度 0 上分片的 DTensors。这提供了更好的与模型并行技术和其他需要操作单个参数的功能的组合性，允许分片状态字典由 DTensor 表示而无需任何通信，并通过 DTensor 提供了更简单的元设备初始化流程。例如， FSDP2 解锁了更细粒度的张量级量化，特别是 Float8 张量量化，我们将在结果部分展示。</p><p>作为从 FSDP1 重写为 FSDP2 的一部分， FSDP2 通过避免使用记录流实现了改进的内存管理系统。这实现了确定性的内存释放，因此相对于 FSDP1，每 GPU 的内存需求更低。例如，在 Llama 2 7B 上， FSDP2 记录了比 FSDP1 平均低 7% 的 GPU 内存。</p><p>此外，通过编写高效的内核来执行多张量全收集和减少分散， FSDP2 显示出与 FSDP1 相当的性能，并且有轻微的性能提升——使用 Llama 2 7B， FSDP2 显示出平均 1.5% 的吞吐量提升。</p><p>性能提升是采用两个小性能改进的结果。首先，仅为 FP32 减少分散运行一个除法内核（将本地 FP32 减少分散梯度除以世界大小，而不是两步预除和后除世界大小的平方根）。其次，在 TorchTitan 中， FSDP2 集成了默认情况下在正向传递期间不分片 Transformer 层中的最后一个块，因为它将在反向传递开始时立即重新收集。因此，我们可以跳过一轮通信延迟。</p><p><strong>用法</strong>： TorchTitan 已完全集成 FSDP2 作为默认并行性，<code>data_parallel_shard_degree</code> 是命令行或 TOML 文件中的控制维度。请注意，为了便于使用，将 <code>data_parallel_shard_degree</code> 保留为 -1 （默认值）意味着简单地使用所有可用的 GPU （即无需指定实际的世界大小）。</p><h3 id="混合分片数据并行" tabindex="-1">混合分片数据并行 <a class="header-anchor" href="#混合分片数据并行" aria-label="Permalink to “混合分片数据并行”">​</a></h3><p>混合分片数据并行（HSDP）是 FSDP 的扩展（Zhang et al., 2022），它能够使用更大的总世界大小。在 FSDP 中，所有设备都是单个全局组的一部分，所有通信都在该组中启用。然而，在某些时候，增加更多的计算会被由于增加更多需要平等通信参与的参与者而增加的通信开销所抵消。这是由于集体通信的延迟与参与者的总数直接相关。在这个饱和点， FSDP 吞吐量将有效地趋于平稳，即使增加了更多的计算。</p><p>HSDP 通过在原始全局组（海洋）内创建较小的分片组（岛屿）在一定程度上避免了这一点。每个分片组在其内部运行 FSDP，并在反向传递期间以设定的频率同步分片组之间的梯度，以确保维护全局梯度。这确保了快速的通信，因为参与者的总通信大小现在是原始世界大小的一小部分，并且唯一的全局通信是分片组之间的梯度 All-Reduce。通过使用分片组，我们已经看到 HSDP 可以将总世界大小扩展到 FSDP 通信饱和点的 3-6 倍（这将根据网络互连的速度而变化）。</p><p>TorchTitan 通过两个用户可配置的设置（分片组大小和复制组大小）使运行 HSDP 变得容易，可以从命令行或 TOML 文件中配置。</p><p><strong>用法</strong>：在 TorchTitan 中通过修改 <code>data_parallel_shard_degree</code> 来控制分片组大小以启用 HSDP。这实际上是将在其相应组成员中运行 FSDP 分片的 GPU 组计数。从那里，我们必须指定 <code>data_parallel_replicate_degree</code>，它控制我们创建多少个分片组。复制和分片度的乘积必须等于总世界大小。示例——在 128 GPU 集群上，我们可能会发现分片 16 个 GPU 足以满足模型大小。因此，我们将 <code>data_parallel_shard_degree</code> 设置为 16，并将 <code>data_parallel_replicate_degree</code> 相应地设置为 8，这意味着我们将有 8 组 16 个 GPU 来填满 128 的总世界大小。</p><h3 id="张量并行" tabindex="-1">张量并行 <a class="header-anchor" href="#张量并行" aria-label="Permalink to “张量并行”">​</a></h3><p>TP 将 Transformer 层的注意力和前馈网络（MLP）模块分区到多个设备上，其中使用的设备数量是 TP 度。这允许多个 GPU 协作处理一个 Transformer 层，否则该层将超出单个 GPU 的能力，代价是添加 All-Reduce/All-Gather/Reduce-Scatter 操作以同步中间结果。</p><p>由于 TP 引入了额外的集体，它需要在快速网络（即 NVLink）上发生。在训练 LLM 时， TP 通常与 FSDP 结合使用，其中 TP 在节点内分片， FSDP 在节点间分片，以在不同 DeviceMesh 维度上创建 2D 分层分片。</p><p><strong>用法</strong>：由于 TP 和 SP 之间的协同关系， TorchTitan 原生将这两者捆绑在一起，并通过命令行或 TOML 条目中的 <code>tensor_parallel_degree</code> 设置共同控制。例如，将此设置为 2 意味着节点内的 2 个 GPU 将通过 TP 共享每个 Transformer 层的注意力和 MLP 模块的计算负载，并通过序列并行共享归一化/丢弃层。损失并行通过上下文管理器实现，因为它需要控制模型正向计算之外的损失计算。可以通过 <code>enable_loss_parallel</code> 启用。</p><h3 id="流水线并行" tabindex="-1">流水线并行 <a class="header-anchor" href="#流水线并行" aria-label="Permalink to “流水线并行”">​</a></h3><p>我们暴露了几个参数来配置 PP。<code>pipeline_parallel_degree</code> 控制参与 PP 的排名数量。<code>pipeline_parallel_split_points</code> 接受一个字符串列表，表示在执行拆分之前的层的完全限定名称。因此，流水线阶段的总数 $V$ 将由该列表的长度决定。<code>pipeline_parallel_schedule</code> 接受要使用的调度的名称。如果调度是多阶段的，则应为每个流水线排名分配 $V&gt;1$ 个阶段，否则 $V==1$。<code>pipeline_parallel_microbatches</code> 控制将数据批次拆分为多少个微批次。</p><h3 id="激活检查点" tabindex="-1">激活检查点 <a class="header-anchor" href="#激活检查点" aria-label="Permalink to “激活检查点”">​</a></h3><p>TorchTitan 提供了两种类型的选择性激活检查点，允许在内存和重新计算之间进行更细致的权衡。具体来说，我们提供了选择性地检查点&quot;每层&quot;或&quot;每操作&quot;的选项。每操作的目标是释放由更快重新计算的操作使用的内存，并保存较慢重新计算的操作的中间结果（内存），从而提供更有效的吞吐量/内存权衡。</p><p><strong>用法</strong>： AC 通过命令行或 TOML 文件中的两行设置启用。具体来说，<code>mode</code> 可以是 <code>none</code>、<code>selective</code> 或 <code>full</code>。当设置为 <code>selective</code> 时，则使用下一个配置 <code>selective_ac_type</code>，它可以是一个正整数以启用选择性层检查点，或 <code>op</code> 以启用选择性操作检查点。每层接受一个整数输入以指导检查点策略，其中 1 = 检查点每层（与 <code>full</code> 相同）， 2 = 检查点每隔一层， 3 = 检查点每隔三层，等等。每操作由 <code>parallelize_llama.py</code> 中的 <code>_save_list</code> 策略驱动，该策略标记高算术强度操作，如 matmul （矩阵乘法）和 SDPA （缩放点积注意力）以保存中间结果，同时允许其他较低强度操作重新计算。请注意，为了平衡总吞吐量，仅每隔一个 matmul 被标记为保存。</p><h3 id="asynctp" tabindex="-1">AsyncTP <a class="header-anchor" href="#asynctp" aria-label="Permalink to “AsyncTP”">​</a></h3><p>AsyncTP 中使用的 SymmetricMemory 集体比标准 NCCL 集体更快，并通过让每个 GPU 分配一个相同的内存缓冲区以提供直接的 P2P 访问来操作。SymmetricMemory 依赖于节点内的 NVSwitch，因此通常仅适用于 H100 或更新的 GPU。</p><p><strong>用法</strong>： AsyncTP 在 TorchTitan TOML 配置文件的实验部分中启用，并通过 <code>enable_async_tensor_parallel</code> 布尔设置打开或关闭。</p><h3 id="在-torchtitan-中自定义-fsdp2-混合精度" tabindex="-1">在 TorchTitan 中自定义 FSDP2 混合精度 <a class="header-anchor" href="#在-torchtitan-中自定义-fsdp2-混合精度" aria-label="Permalink to “在 TorchTitan 中自定义 FSDP2 混合精度”">​</a></h3><p>混合精度由 <code>apply_fsdp</code> 函数中的 <code>MixedPrecisionPolicy</code> 类控制。在 TorchTitan 中默认使用 <code>param_dtype</code> 为 BF16，<code>reduce_dtype</code> 默认为 FP32。FP32 中的 <code>reduce_dtype</code> 意味着反向传递中的减少分散用于梯度计算将在 FP32 中进行，以帮助最大化梯度更新的稳定性和精度。</p>`,149)])])}const T=e(r,[["render",t]]);export{P as __pageData,T as default};
